/*
 * This file was generated by the Gradle 'init' task.
 */

plugins {
    id("buildlogic.server-conventions")
}

// Maven surefire excludes *Test classes; failsafe runs them as ITs (require Docker/Testcontainers).
tasks.named<Test>("test") {
    exclude("**/*Test.class", "**/*Test\$*.class")
}

// Extend the it task registered by java-conventions to also include *Test* patterns,
// since all tests in this module require Docker/Testcontainers.
tasks.named<Test>("it") {
    description = "Runs integration tests (require Docker)"
    include("**/*Test.class", "**/*Test\$*.class")
}

dependencies {
    implementation(project(":camunda-spring-boot-starter"))
    testImplementation(project(":camunda-process-test-spring"))
    testImplementation(project(":camunda-process-test-java"))
    testImplementation(project(":camunda-process-test-json-test-cases"))
    testImplementation(libs.org.springframework.boot.spring.boot.starter.test)
    testImplementation(libs.org.springframework.boot.spring.boot.test)
    testImplementation(libs.org.mockito.mockito.core)
    testImplementation(libs.org.awaitility.awaitility)
    testImplementation(libs.org.springframework.spring.test)
    testImplementation(libs.org.wiremock.integrations.wiremock.spring.boot)
}

description = "Camunda Process Test Example"
